1	const BASE_PREMIUM = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	} as const;
9	
10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType };
13	
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
17	
18	export function calculateBasePremium(items: Item[]): number {
19	  const groups = new Map<ItemType, number>();
20	  for (const item of items) {
21	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
22	  }
23	
24	  let total = 0;
25	  for (const [type, count] of groups) {
26	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
27	      total += BLOCK_PREMIUM;
28	    } else {
29	      total += count * BASE_PREMIUM[type];
30	    }
31	  }
32	  return total;
33	}
